-  static std::vector<std::vector<std::complex<float>>> stft(std::vector<float> &x,
-                                                            int n_fft, int n_hop,
-                                                            const std::string &win, bool center,
-                                                            const std::string &mode){
-    Vectorf map_x = Eigen::Map<Vectorf>(x.data(), x.size());
